function makeTransformValues (c, r) {
    var m = [];
    var x1 = c[0], y1 = c[1], x2 = c[2], y2 = c[3];
    var det = Math.pow(x1,2) + (-2 * x2 * x1) + Math.pow(x2,2) + Math.pow(y1,2) + Math.pow(y2,2) + (-2 * y1 * y2);

    if(det === 0) {
        return null; // no solution;
    }

    m[0]  = (x1 - x2) / det;
    m[1]  = (y2 - y1) / det;
    m[2]  = (x2 - x1) / det;
    m[3]  = (y1 - y2) / det;
    m[4]  = (y1 - y2) / det;
    m[5]  = (x1 - x2) / det;
    m[6]  = (y2 - y1) / det;
    m[7]  = (x2 - x1) / det;
    m[8]  = (Math.pow(x2,2) + (-1 * x1 * x2) + Math.pow(y2,2) + (-1 * y1 * y2)) / det;
    m[9]  = ((x2 * y1) + (-1 * x1 * y2)) / det;
    m[10] = (Math.pow(x1,2) + (-1 * x2 * x1) + Math.pow(y1,2) + (-1 * y1 * y2)) / det;
    m[11] = ((x1 * y2) + (-1 * x2 * y1)) / det;
    m[12] = ((x1 * y2) + (-1 * x2 * y1)) / det;
    m[13] = (Math.pow(x2,2) + (-1 * x1 * x2) + Math.pow(y2,2) + (-1 * y1 * y2)) / det;
    m[14] = ((x2 * y1) + (-1 * x1 * y2)) / det;
    m[15] = (Math.pow(x1,2) + (-1 * x2 * x1) + Math.pow(y1,2) + (-1 * y1 * y2)) / det;

    function _transform(p_c, transform) {
        var dst = [];
        var i, j, temp = 0;

        for (i = 0; i < 4; i++) {
            temp = 0;
            for (j = 0; j < 4; j++) {
                temp += transform[i * 4 + j] * p_c[j];
            }
            dst[i] = temp;
        }

        return dst;
    }

    return _transform(r, m);
}

 function pointsToWorld(cv, tv) {
    var p = cv;
    var g = tv;
    var dst = {};

    if(!p || p.length < 1 ||!g || g.length < 1)
        return null;

    // X = ax + by + c
    // Y = bx - ay + d
    dst.X = (g[0] * p[0]) + (     g[1] * p[1]) + g[2];
    dst.Y = (g[1] * p[0]) + (-1 * g[0] * p[1]) + g[3];

    return dst;
}

